script.text:

function active$FormLocation(f) {f.add_onResponseComplete(on$FormLocation$ResponseComplete);}
function close$FormLocation(f) {try {f.remove_onResponseComplete(on$FormLocation$ResponseComplete)} catch (ex) {}}
function on$FormLocation$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_vi_tri');
      break;
    default:
      break;
  }
}

      &ScriptIrregular;
